var options = {
    hostname: "10.1.32.20",
    port: 81,
    path: "/api/events?subscribe=registers&coils=0-255&hr=0-31&di=0-255&ir=0-31",
    method: "GET",
    headers: {
        "Authorization": "Basic YXBpX3VzZXI6ITIzUGFzc3dvcmQ="
    }
};

var currentEvent = "";
var req = http.request(options, function(res) {
    node.status({fill:"green",shape:"dot",text:"connected"});
    var buffer = "";
    res.on("data", function(chunk) {
        buffer += chunk.toString();
        var lines = buffer.split(String.fromCharCode(10));
        buffer = lines.pop();
        for (var i = 0; i < lines.length; i++) {
            var line = lines[i].trim();
            if (line.indexOf("event: ") === 0) {
                currentEvent = line.substring(7);
            }
            if (line.indexOf("data: ") === 0 && currentEvent === "register") {
                try {
                    var data = JSON.parse(line.substring(6));
                    var typeMap = {
                        "hr": "holding",
                        "ir": "input",
                        "coil": "coils",
                        "di": "dis input"
                    };
                    node.send({
                        payload: {
                            register: data.addr,
                            value: data.value,
                            type: typeMap[data.type] || data.type
                        }
                    });
                } catch(e) {}
            }
        }
    });
    res.on("end", function() {
        node.status({fill:"red",shape:"ring",text:"disconnected"});
    });
});

req.on("error", function(e) {
    node.status({fill:"red",shape:"ring",text:e.message});
    node.error(e.message);
});

req.end();
